import { toString as qrToString } from 'qrcode';
import * as React from 'react';
import { useEffect, useState } from 'react';
import { Pane } from '../../components/design-system/Pane.js';
import type { KeyboardEvent } from '../../ink/events/keyboard-event.js';
import { Box, Text } from '../../ink.js';
import { useKeybinding } from '../../keybindings/useKeybinding.js';
import type { LocalJSXCommandOnDone } from '../../types/command.js';

type Platform = 'ios' | 'android';

type Props = {
  onDone: () => void;
};

const PLATFORMS: Record<Platform, { url: string }> = {
  ios: {
    url: 'https://apps.apple.com/app/claude-by-anthropic/id6473753684',
  },
  android: {
    url: 'https://play.google.com/store/apps/details?id=com.anthropic.netrunner',
  },
};

function MobileQRCode({ onDone }: Props): React.ReactNode {
  const [platform, setPlatform] = useState<Platform>('ios');
  const [qrCodes, setQrCodes] = useState<Record<Platform, string>>({
    ios: '',
    android: '',
  });

  useEffect(() => {
    const generateQRCodes = async (): Promise<void> => {
      const [ios, android] = await Promise.all([
        qrToString(PLATFORMS.ios.url, {
          type: 'utf8',
          errorCorrectionLevel: 'L',
        }),
        qrToString(PLATFORMS.android.url, {
          type: 'utf8',
          errorCorrectionLevel: 'L',
        }),
      ]);

      setQrCodes({ ios, android });
    };

    generateQRCodes().catch(() => {});
  }, []);

  useKeybinding('confirm:no', onDone, {
    context: 'Confirmation',
  });

  const handleKeyDown = (event: KeyboardEvent): void => {
    if (event.key === 'q' || (event.ctrl && event.key === 'c')) {
      event.preventDefault();
      onDone();
      return;
    }

    if (
      event.key === 'tab' ||
      event.key === 'left' ||
      event.key === 'right'
    ) {
      event.preventDefault();
      setPlatform(prev => (prev === 'ios' ? 'android' : 'ios'));
    }
  };

  const qrCode = qrCodes[platform];
  const lines = qrCode.split('\n').filter(line => line.length > 0);
  const isIos = platform === 'ios';
  const isAndroid = platform === 'android';

  return (
    <Pane>
      <Box
        flexDirection="column"
        tabIndex={0}
        autoFocus={true}
        onKeyDown={handleKeyDown}
      >
        <Text> </Text>
        <Text> </Text>
        {lines.map((line, index) => (
          <Text key={index}>{line}</Text>
        ))}
        <Text> </Text>
        <Text> </Text>
        <Box flexDirection="row" gap={2}>
          <Text>
            <Text bold={isIos} underline={isIos}>
              iOS
            </Text>
            <Text dimColor={true}> / </Text>
            <Text bold={isAndroid} underline={isAndroid}>
              Android
            </Text>
          </Text>
          <Text dimColor={true}>(tab to switch, esc to close)</Text>
        </Box>
        <Text dimColor={true}>{PLATFORMS[platform].url}</Text>
      </Box>
    </Pane>
  );
}

export async function call(onDone: LocalJSXCommandOnDone): Promise<React.ReactNode> {
  return <MobileQRCode onDone={onDone} />;
}
